mcqs.question:
What will be the output of the following code?

#include <iostream>
using namespace std;
class Test {
    int x;
public:
    Test(int val) : x(val) {}
    ~Test() { cout << "Destructor "; }
};
int main() {
    Test t(5);
    return 0;
}

Consider the following code:

#include <iostream>
using namespace std;
class Base {
protected:
    int x;
};
class Derived : public Base {
public:
    void display() { cout << x; }
};
int main() {
    Derived d;
    d.display();
    return 0;
}

What will be the output and why?

What will be the output of the following code?

#include <iostream>
using namespace std;
class Counter {
    static int count;
    int id;
public:
    Counter() { id = ++count; }
    void show() { cout << id << " "; }
    static void display() { cout << count << " "; }
};
int Counter::count = 0;
int main() {
    Counter c1, c2, c3;
    c1.show();
    c2.show();
    Counter::display();
    return 0;
}
